package com.veetu.vadagai.payment;import com.veetu.vadagai.common.ApiResponse;import com.veetu.vadagai.payment.PaymentDtos.*;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/payments") @RequiredArgsConstructor public class PaymentController{private final PaymentService svc;@GetMapping ApiResponse<Page<PaymentResponse>> mine(@PageableDefault(size=20) Pageable p){return ApiResponse.ok("Payments",svc.mine(p));}@PostMapping ApiResponse<PaymentResponse> create(@Valid @RequestBody PaymentRequest r){return ApiResponse.ok("Razorpay order created",svc.create(r));}@PostMapping("/razorpay/webhook") ApiResponse<PaymentResponse> webhook(@RequestBody RazorpayWebhook w){return ApiResponse.ok("Payment synced",svc.webhook(w));}}
